import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PRIMARY_BLUE = '#007BFF';

const AuthPage = () => {
  const navigate = useNavigate();
  const [authMode, setAuthMode] = useState('register'); // 'login' | 'register'
  const [role, setRole] = useState('student'); // 'student' | 'tutor'
  const [isLoading, setIsLoading] = useState(false);

  // Shared fields
  const [fullName, setFullName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [age, setAge] = useState('');
  const [gender, setGender] = useState('');
  const [password, setPassword] = useState('');

  // Student fields
  const [grade, setGrade] = useState('');
  const [schoolName, setSchoolName] = useState('');

  // Tutor fields
  const [telegram, setTelegram] = useState('');
  const [educationLevel, setEducationLevel] = useState('');
  const [achievements, setAchievements] = useState('');
  const [docsFiles, setDocsFiles] = useState([]);
  const [trialVideoUrl, setTrialVideoUrl] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      if (authMode === 'register') {
        const formData = new FormData();

        formData.append('fullName', fullName);
        formData.append('phone', phone);
        formData.append('password', password);
        formData.append('role', role);

        if (age) formData.append('age', age);
        if (gender) formData.append('gender', gender);

        if (role === 'student') {
          if (grade) formData.append('grade', grade);
          if (schoolName) formData.append('schoolName', schoolName);
        }

        if (role === 'tutor') {
          formData.append('email', email);
          formData.append('telegramUsername', telegram);
          if (educationLevel) formData.append('educationLevel', educationLevel);
          if (achievements) formData.append('achievements', achievements);
          if (trialVideoUrl) formData.append('trialVideoUrl', trialVideoUrl);

          docsFiles.forEach((file) => {
            formData.append('docs', file);
          });
        }

        const response = await axios.post(
          'http://localhost:5000/api/auth/register',
          formData,
          {
            headers: {
              'Content-Type': 'multipart/form-data'
            }
          }
        );

        const { token, user } = response.data;

        if (token) {
          localStorage.setItem('ethioBooksToken', token);
        }
        if (user) {
          localStorage.setItem('ethioBooksUser', JSON.stringify(user));
        }

        if (user?.role === 'tutor') {
          alert('Registration successful! Please wait for Admin approval.');
        } else if (user?.role === 'student') {
          navigate('/dashboard');
        }
      } else {
        // Login
        const payload = {
          password
        };

        // Prefer email if provided, otherwise phone
        if (email) {
          payload.email = email;
        } else if (phone) {
          payload.phone = phone;
        }

        const response = await axios.post(
          'http://localhost:5000/api/auth/login',
          payload
        );

        const { token, user } = response.data;

        if (token) {
          localStorage.setItem('ethioBooksToken', token);
        }
        if (user) {
          localStorage.setItem('ethioBooksUser', JSON.stringify(user));
        }

        if (user?.role === 'tutor') {
          // You can route tutors to a pending/overview page
          navigate('/tutor');
        } else if (user?.role === 'admin') {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Something went wrong. Please try again.';
      alert(message);
    } finally {
      setIsLoading(false);
    }
  };

  const isTutor = role === 'tutor';
  const isStudent = role === 'student';

  return (
    <div className="min-h-screen flex items-center justify-center bg-white">
      <div className="w-full max-w-5xl mx-4 grid md:grid-cols-2 gap-8">
        {/* Left: Branding / Info */}
        <div className="hidden md:flex flex-col justify-center space-y-6">
          <div>
            <h1
              className="text-4xl font-extrabold tracking-tight"
              style={{ color: PRIMARY_BLUE }}
            >
              Ethio Books
            </h1>
            <p className="mt-3 text-gray-600 text-sm">
              Learn and teach with Ethiopia&apos;s premier online tutoring platform.
              Join as a student or become a tutor and share your knowledge.
            </p>
          </div>

          <div className="space-y-3">
            <div className="flex items-center space-x-3">
              <span
                className="w-9 h-9 flex items-center justify-center rounded-full text-white font-semibold shadow-md"
                style={{ backgroundColor: PRIMARY_BLUE }}
              >
                1
              </span>
              <div>
                <p className="font-semibold text-gray-800 text-sm">
                  Choose your role
                </p>
                <p className="text-gray-500 text-xs">
                  Switch between Student and Tutor to see tailored fields.
                </p>
              </div>
            </div>
            <div className="flex items-center space-x-3">
              <span
                className="w-9 h-9 flex items-center justify-center rounded-full text-white font-semibold shadow-md"
                style={{ backgroundColor: PRIMARY_BLUE }}
              >
                2
              </span>
              <div>
                <p className="font-semibold text-gray-800 text-sm">
                  Complete the form
                </p>
                <p className="text-gray-500 text-xs">
                  Provide accurate information so we can match you effectively.
                </p>
              </div>
            </div>
            <div className="flex items-center space-x-3">
              <span
                className="w-9 h-9 flex items-center justify-center rounded-full text-white font-semibold shadow-md"
                style={{ backgroundColor: PRIMARY_BLUE }}
              >
                3
              </span>
              <div>
                <p className="font-semibold text-gray-800 text-sm">
                  Get started
                </p>
                <p className="text-gray-500 text-xs">
                  Students access lessons. Tutors are reviewed and then activated.
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Right: Auth Card */}
        <div className="bg-white rounded-2xl shadow-xl border border-gray-100 p-6 sm:p-8">
          {/* Auth mode toggle (Login / Register) */}
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-semibold text-gray-800">
              {authMode === 'register' ? 'Create your account' : 'Welcome back'}
            </h2>
            <div className="flex text-xs bg-gray-100 rounded-full p-1">
              <button
                type="button"
                onClick={() => setAuthMode('login')}
                className={`px-3 py-1 rounded-full transition-all ${
                  authMode === 'login'
                    ? 'bg-white text-gray-900 shadow-sm'
                    : 'text-gray-500 hover:text-gray-800'
                }`}
              >
                Login
              </button>
              <button
                type="button"
                onClick={() => setAuthMode('register')}
                className={`px-3 py-1 rounded-full transition-all ${
                  authMode === 'register'
                    ? 'bg-white text-gray-900 shadow-sm'
                    : 'text-gray-500 hover:text-gray-800'
                }`}
              >
                Register
              </button>
            </div>
          </div>

          {/* Role Toggle (Student / Tutor) */}
          <div className="relative mb-6">
            <div className="flex bg-gray-100 rounded-full p-1 relative">
              <div
                className={`absolute top-1 bottom-1 w-1/2 bg-white rounded-full shadow-sm transform transition-transform duration-300 ${
                  role === 'student' ? 'translate-x-0' : 'translate-x-full'
                }`}
              />
              <button
                type="button"
                onClick={() => setRole('student')}
                className={`relative z-10 flex-1 text-center text-xs sm:text-sm font-medium py-2 rounded-full transition-colors ${
                  role === 'student'
                    ? 'text-gray-900'
                    : 'text-gray-500 hover:text-gray-800'
                }`}
              >
                Student
              </button>
              <button
                type="button"
                onClick={() => setRole('tutor')}
                className={`relative z-10 flex-1 text-center text-xs sm:text-sm font-medium py-2 rounded-full transition-colors ${
                  role === 'tutor'
                    ? 'text-gray-900'
                    : 'text-gray-500 hover:text-gray-800'
                }`}
              >
                Tutor
              </button>
            </div>
          </div>

          {/* Form */}
          <form className="space-y-4" onSubmit={handleSubmit}>
            {/* Full Name */}
            <div>
              <label className="block text-xs font-medium text-gray-700 mb-1">
                Full Name
              </label>
              <input
                type="text"
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                placeholder="Enter your full name"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                required={authMode === 'register'}
              />
            </div>

            {/* Email (especially for tutors + login) */}
            {(!isStudent && authMode === 'login') || (isTutor && authMode === 'register') ? (
              <div>
                <label className="block text-xs font-medium text-gray-700 mb-1">
                  {isTutor ? 'Gmail Address' : 'Email'}
                </label>
                <input
                  type="email"
                  className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                  placeholder={isTutor ? 'yourname@gmail.com' : 'you@example.com'}
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required={(!isStudent && authMode === 'login') || (isTutor && authMode === 'register')}
                />
                {isTutor && authMode === 'register' && (
                  <p className="mt-1 text-[11px] text-gray-500">
                    Tutors must register with a <span className="font-semibold">@gmail.com</span>{' '}
                    address.
                  </p>
                )}
              </div>
            ) : null}

            {/* Phone */}
            {(isStudent || authMode === 'register') && (
              <div className="grid sm:grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Phone
                  </label>
                  <input
                    type="tel"
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                    placeholder="+251 9..."
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required={authMode === 'register' || isStudent}
                  />
                </div>

                {/* Age */}
                {authMode === 'register' && (
                  <div>
                    <label className="block text-xs font-medium text-gray-700 mb-1">
                      Age
                    </label>
                    <input
                      type="number"
                      min="7"
                      max="90"
                      className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                      placeholder="Age"
                      value={age}
                      onChange={(e) => setAge(e.target.value)}
                    />
                  </div>
                )}
              </div>
            )}

            {/* Gender */}
            {authMode === 'register' && (
              <div>
                <label className="block text-xs font-medium text-gray-700 mb-1">
                  Gender
                </label>
                <select
                  className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                  value={gender}
                  onChange={(e) => setGender(e.target.value)}
                >
                  <option value="">Select gender</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                  <option value="prefer_not_to_say">Prefer not to say</option>
                </select>
              </div>
            )}

            {/* Student-specific fields (Register only) */}
            {authMode === 'register' && isStudent && (
              <div className="grid sm:grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Grade
                  </label>
                  <select
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                    value={grade}
                    onChange={(e) => setGrade(e.target.value)}
                  >
                    <option value="">Select grade</option>
                    {[7, 8, 9, 10, 11, 12].map((g) => (
                      <option key={g} value={g}>
                        Grade {g}
                      </option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    School Name
                  </label>
                  <input
                    type="text"
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                    placeholder="Your school name"
                    value={schoolName}
                    onChange={(e) => setSchoolName(e.target.value)}
                  />
                </div>
              </div>
            )}

            {/* Tutor-specific fields (Register only) */}
            {authMode === 'register' && isTutor && (
              <>
                <div className="grid sm:grid-cols-2 gap-3">
                  <div>
                    <label className="block text-xs font-medium text-gray-700 mb-1">
                      Telegram Username
                    </label>
                    <input
                      type="text"
                      className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                      placeholder="@yourusername"
                      value={telegram}
                      onChange={(e) => setTelegram(e.target.value)}
                    />
                    <p className="mt-1 text-[11px] text-gray-500">
                      Must start with <span className="font-semibold">@</span>.
                    </p>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-gray-700 mb-1">
                      Education Level
                    </label>
                    <input
                      type="text"
                      className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                      placeholder="e.g. BSc in Maths"
                      value={educationLevel}
                      onChange={(e) => setEducationLevel(e.target.value)}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1">
                    Achievements (optional)
                  </label>
                  <textarea
                    rows={2}
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition resize-none"
                    placeholder="Olympiad awards, teaching experience, etc."
                    value={achievements}
                    onChange={(e) => setAchievements(e.target.value)}
                  />
                </div>

                <div className="grid sm:grid-cols-2 gap-3">
                  <div>
                    <label className="block text-xs font-medium text-gray-700 mb-1">
                      Documents (certificates, transcripts)
                    </label>
                    <input
                      type="file"
                      multiple
                      className="w-full text-xs text-gray-600 file:mr-2 file:py-1.5 file:px-3 file:rounded-full file:border-0 file:text-xs file:font-medium file:text-white file:bg-blue-500 hover:file:bg-blue-600 cursor-pointer"
                      onChange={(e) => setDocsFiles(Array.from(e.target.files || []))}
                    />
                    <p className="mt-1 text-[11px] text-gray-500">
                      You can upload multiple files.
                    </p>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-gray-700 mb-1">
                      Trial Video (YouTube URL)
                    </label>
                    <input
                      type="url"
                      className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                      placeholder="https://www.youtube.com/watch?v=..."
                      value={trialVideoUrl}
                      onChange={(e) => setTrialVideoUrl(e.target.value)}
                    />
                    <p className="mt-1 text-[11px] text-gray-500">
                      Paste the YouTube link to your trial teaching video.
                    </p>
                  </div>
                </div>
              </>
            )}

            {/* Password */}
            <div>
              <label className="block text-xs font-medium text-gray-700 mb-1">
                Password
              </label>
              <input
                type="password"
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 transition"
                placeholder="Enter a secure password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={isLoading}
              className="w-full mt-2 inline-flex items-center justify-center px-4 py-2.5 text-sm font-semibold rounded-lg text-white shadow-md transition-all disabled:cursor-not-allowed"
              style={{
                backgroundColor: PRIMARY_BLUE,
                boxShadow: '0 10px 15px -3px rgba(0,123,255,0.35)'
              }}
              onMouseEnter={(e) => {
                if (!isLoading) e.currentTarget.style.backgroundColor = '#0064cc';
              }}
              onMouseLeave={(e) => {
                if (!isLoading) e.currentTarget.style.backgroundColor = PRIMARY_BLUE;
              }}
            >
              {isLoading && (
                <span className="mr-2 inline-block h-4 w-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
              )}
              {isLoading
                ? 'Submitting...'
                : authMode === 'register'
                ? `Register as ${role === 'student' ? 'Student' : 'Tutor'}`
                : 'Login'}
            </button>

            {/* Small helper text */}
            <p className="text-[11px] text-gray-500 text-center mt-1">
              By continuing, you agree to Ethio Books&apos; terms and privacy policy.
            </p>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
